var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"역시 넌 운이 좋은 편이야. 그렇잖아도 무료함을 달래느라 고생 깨나 하던 참이거든.","JPN":"やはり其方は運の良い奴じゃな。ちょうど退屈を紛らわすのに苦労していたところじゃ。","ENG":"Ah, lucky you. I was bored and was looking for something fun.","TWN":"你的運氣果然很好呢，正好我最近拼命地想要打發無聊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"요즘 탐정 사무소로 들어오는 사연도 영 시답잖은 것들뿐이고 말이야.","JPN":"最近、探偵事務所に舞い込む話も、揃いも揃ってインパクトに欠けるものばかりじゃったからのう。","ENG":"There hasn't been any serious cases lately, you know.","TWN":"最近偵探事務所接的都是些''怎樣都好啦''的案子。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"가출한 고양이 찾기 같은 일거리 따위, 듣고 있어 봤자 지루하기만 할 뿐이지.","JPN":"家出した猫を捜す仕事なんかもそうじゃ。聞いただけであくびが出そうじゃ。","ENG":"I would have killed myself if I had to go find another cat that ran away from its boring home.","TWN":"幫人找離家出走的貓什麼的，聽了就無聊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내가 기대했던 건 음습하고 질척질척하면서 배덕적인 치정극이거든.","JPN":"妾が期待していたのは、陰湿でドロドロで背徳的な、痴情劇なのじゃ。","ENG":"Where have all the filthy, immoral relationship issues gone?","TWN":"我期待的可是那種陰暗糾纏又背德的電視劇啊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이혼, 불륜, 고부갈등, 파국...... 그런 종류 있잖아?","JPN":"離婚、不倫、嫁姑問題、破局……色々とあるじゃろう？","ENG":"Divorces, cheating husbands and wives, conflict between in-laws, ruined families... You know, those sorts of things.","TWN":"離婚，外遇，婆媳矛盾，決裂……不是有這種的嘛？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그런데 이 세상의 인간들은 사랑도 뭣도 참 따분하게 하더군. 기쁨에 겨워 숨이 끊어질 때까지 밟아 주고 싶을 때가 많아.","JPN":"ところがこの世界の人間たちときたら、恋だの愛だの退屈にもほどがある。\\n拍手代わりに思いっきり踏みつけて、息の根を止めてやりたいくらいじゃ。","ENG":"As it turns out, most people in this world lead boring love lives. Sometimes I want to trample on them until they die of happiness.","TWN":"不過這世上的人類啊，不管是愛情還是什麼，真的都太無聊了。每當我厭倦了喜悅，都想把他們踩到斷氣。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"덕분에 티브이에 있던 드라마도 전부 완주해 버렸지.","JPN":"おかげでテレビでやってるドラマを完全制覇してしまったのじゃ。","ENG":"To relieve my boredom, I've watched all the soap operas on TV.","TWN":"多虧他們，我把電視上播的肥皂劇都快完了。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이젠 점 하나 찍었다고 주변 사람들이 몰라 보는 정도론 흥이 나질 않아.","JPN":"もうホクロを一つ付けただけで他人になりきるような展開を見せられても、突っ込む気にもならぬ。","ENG":"I've watched so many of them that I've grown numb to the thrills they provoke.","TWN":"什麼女主角為了復仇去點了顆痣，周圍的人就認不出她了，看到這種情節我都覺得沒意思。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그러다 보니...... 이 몸의 비상한 두뇌가 문득 멋진 발상을 떠올리더군.","JPN":"そうしておると……妾の素晴らしい頭脳が、あるアイデアをひらめいたのじゃ。","ENG":"And, being smart as I am, I ended up coming up with a solution.","TWN":"這麼一說……我這聰明的腦袋裡突然閃過一個好主意。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"바로 지금까지 구경만 해 오던 치정극의 한복판에 몸소 뛰어드는 거야.","JPN":"今まで眺めてばかりいた痴情劇の真っ只中に、自ら飛び込んでみようとな。","ENG":"How exciting would it be if I were to become the one to experience all these wild love affairs?","TWN":"那就是自己跳進我至今看過的那些電視劇裡。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"후훗. 수많은 역경을 돌파하고 개미들의 질투 속에서 승자가 되는 모습이 눈에 훤하군.","JPN":"ふふっ、妾は数多の逆境を乗り越え、虫どもの羨望を受けながら勝者として君臨しよう。その姿が今にも目に浮かぶようじゃ。","ENG":"Heh heh. I can already see myself going through numerous obstacles and emerging victorious among the pathetic, jealous losers.","TWN":"呵呵，突破重重逆境，在螻蟻們嫉妒中成為勝利者的身姿，我眼前已經浮現出那些畫面了。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"자고로 치정극이란 상대역도 있어야 하는 법이지만......","JPN":"さて、今から痴情劇を演じるとなると、当然ながら相手役が必要じゃが……","ENG":"But I can't do this without a person I'd be in love with.","TWN":"但從以前，肥皂劇就必須有人來演對手戲……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"호오, 표정을 보아하니 벌써 누가 그 영예를 얻을지 짐작한 눈치로군.","JPN":"ほう、その表情からすると、もう栄誉ある役を担うスターが誰なのか気付いたようじゃのう。","ENG":"And from your looks I guess you get where this is going.","TWN":"哦，看你的表情，好像已經猜到是誰要獲得這份榮耀了呢。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};